def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60.0 + np.sqrt(cap) * 18 + np.sin(cap) * 12
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 45 * np.cos(cap * 1.7)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 1.1) * 18 / (i + 1)
            for j in range(1, 4):
                fluctuation += np.exp(-usage * j) * 30 / j
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2.2 + 350 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 45 * np.tan(cap / 20)
            for k in range(1, 6):
                if cap % (k + 1.3) < 0.3:
                    fluctuation -= 15 / k
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3)**2.4
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 20 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.1 < 0.7:
                base_priority += 40 * np.sin(cap * 4)
            for m in range(1, 8):
                fluctuation -= np.log1p(usage + m) * 3
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 2.6
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 22 / m
                    if m % 6 == 2:
                        fluctuation += 6 * m
                else:
                    fluctuation += (1 - pwr) * 16 / (m + 2)
                    if m == 14 and usage > 2.8:
                        fluctuation += 28
            if cap % 2.7 < 0.6:
                base_priority += 37 * np.cos(cap * 3.2)
            for n in range(1, 5):
                fluctuation += np.tanh(cap / (n + 1)) * 5
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 3.2
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 28 / n
                    if n % 2 == 0:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 15 / (n + 2)
                    if n == 15 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.8 < 0.4:
                base_priority += 32 * np.cos(cap * 2.5)
            for o in range(1, 10):
                fluctuation -= np.sin(cap * o) * 4 / o
        elif 0.5 < usage <= 1:
            base_priority += 140 * (1 - usage) + np.log1p(usage * 25) * 10
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.08 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 6) * 25
            for p in range(1, 5):
                if int(cap * 1300) % (p + 10) == 1:
                    fluctuation += p * 7
        else:
            base_priority += 350 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 15 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
            for q in range(1, 6):
                fluctuation -= np.cos(cap * q) * 6 / q
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 110
            elif usage < 0.15:
                priority -= 55
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.3:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1300) % (s + 7) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.15:
                priority -= 45
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 100
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3200) % 21 == 0:
            proximity += 18
        if int(cap * 1100) % 25 == 0:
            proximity -= 13
        if int(cap * 220) % 10 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.98:
            for aa in range(1, 9):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.075:
                priority += 50
            if (int(cap * 3200) % 27 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 8):
                if (int(cap * 750) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
